-- Per-dataset preview rows, so a reader can see what is in a file before downloading it.
--
-- Two problems this replaces:
--   * the copy button on each card copied only the card's own description ("edge_psl.xlsx (6 rows)
--     / Purpose: ... / Expected: ...") — text already visible on screen. It copied the label, not
--     the data.
--   * only scale_large had a preview. The other seven could only be judged by downloading them.
--
-- Each entry carries up to 5 rows of key columns (code, soc, title, state, zip, class, exempt,
-- comp) PLUS that row's edge id and expected behaviour — the pairing that previously existed only
-- in the .csv download, which is being removed.
update public.protected_content
set payload = jsonb_set(payload, '{previews}', '{"all_combined": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["CLN-1", "25-4012", "Curators", "CA", "94501", "Regular Full time (FT)", "Non-Exempt", "$41,000.00", "-", "clean; affordable; CA PSL 40h"], ["CLN-2", "13-1041", "Coroners", "NY", "12009", "Regular Full time (FT)", "Non-Exempt", "$41,000.00", "-", "clean family; NY 56h"], ["CLN-3", "29-1124", "Radiation Therapists", "IL", "62311", "Regular Full time (FT)", "Exempt", "$120,000.00", "-", "clean exempt salaried + 4-yr base-salary history"], ["ING-E2", "51-4062", "Patternmakers, Metal and Plastic", "CA", "94501", "Regular Full time (FT)", "E", "$41,900.00", "E2", "exempt as single letter ''E'' -> exempt, out of scope"], ["ING-E2b", "43-3031", "Bookkeeping, Accounting, and Auditing Clerks", "CA", "94501", "Regular Full time (FT)", "N", "$32,000.00", "E2", "''N'' -> non-exempt, in scope"]]}, "clean_baseline": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["CLN-1", "25-4012", "Curators", "CA", "94501", "Regular Full time (FT)", "Non-Exempt", "$41,000.00", "-", "clean; affordable; CA PSL 40h"], ["CLN-2", "13-1041", "Coroners", "NY", "12009", "Regular Full time (FT)", "Non-Exempt", "$41,000.00", "-", "clean family; NY 56h"], ["CLN-3", "29-1124", "Radiation Therapists", "IL", "62311", "Regular Full time (FT)", "Exempt", "$120,000.00", "-", "clean exempt salaried + 4-yr base-salary history"], ["CLN-4", "21-1015", "Rehabilitation Counselors", "WA", "98832", "Regular Full time (FT)", "Non-Exempt", "$36,000.00", "-", "clean; WA no-cap PSL -> floor 0"], ["CLN-5", "27-3043", "Writers and Authors", "TX", "75751", "Regular Full time (FT)", "Non-Exempt", "$34,800.00", "-", "rehired employee \u2014 termination + rehire dates populated"]]}, "edge_fairpay_tax": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["FP-E13", "43-6011", "Executive Secretaries and Executive Administrative Assistants", "TX", "75751", "Regular Full time (FT)", "Non-Exempt", "$24,960.00", "E13", "low-wage large family -> gross-up floored at 0, floor >= basket"], ["FP-E14a", "49-9069", "Precision Instrument and Equipment Repairers, All Other", "IL", "62311", "Regular Full time (FT)", "Non-Exempt", "$30,500.00", "E14", "tier ES -> filing JOINT inferred"], ["FP-E14b", "53-7065", "Stockers and Order Fillers", "IL", "62311", "Regular Full time (FT)", "Non-Exempt", "$24,800.00", "E14", "tier EC -> HEAD_OF_HOUSEHOLD inferred"], ["FP-E15", "29-9093", "Surgical Assistants", "CA", "94501", "Regular Full time (FT)", "Non-Exempt", "$41,800.00", "E15", "waived -> methodology default household (2A2W1C), flagged"], ["FP-E16", "15-1299", "Geographic Information Systems Technologists and Technicians", "GA", "31513", "Regular Full time (FT)", "Non-Exempt", "$43,200.00", "E16", "EC with enrollment 1 (mismatch) -> tier base children, flagged"]]}, "edge_geo": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["GEO-E9", "15-2021", "Mathematicians", "CA", "", "Regular Full time (FT)", "Non-Exempt", "$70,100.00", "E9", "missing ZIP -> home-office fallback, flagged"], ["GEO-E11", "39-3092", "Costume Attendants", "NJ", "12009", "Regular Full time (FT)", "Non-Exempt", "$34,900.00", "E11", "cross-border residence NY / work NJ -> county only if state-consistent, else flagged"], ["GEO-E12", "11-9081", "Lodging Managers", "OH", "43003", "Regular Full time (FT)", "Non-Exempt", "$38,900.00", "E12", "uncovered county (OH) -> degraded basket, flagged"]]}, "edge_healthcare": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["HC-E23", "33-9011", "Animal Control Workers", "WI", "53920", "Regular Full time (FT)", "Non-Exempt", "$22,500.00", "E23", "low employer share (50%) -> Benchmark 1 fail -> verdict review"], ["HC-E24", "49-3092", "Recreational Vehicle Service Technicians", "NY", "12009", "Regular Full time (FT)", "Non-Exempt", "$30,400.00", "E24", "high employer share (100%) -> affordable"], ["HC-E25", "29-1029", "Dentists, All Other Specialists", "TX", "75751", "Regular Full time (FT)", "Non-Exempt", "$136,600.00", "E25", "HDHP choice -> do NOT fail Layer B on it"], ["HC-E26", "33-3011", "Bailiffs", "FL", "32044", "Regular Full time (FT)", "Non-Exempt", "$32,600.00", "E26", "non-compliant/grandfathered -> flagged before benchmarks"], ["HC-E27", "53-7065", "Stockers and Order Fillers", "AZ", "84531", "Regular Full time (FT)", "Non-Exempt", "$24,600.00", "E27", "waived enrollee -> not a false healthcare fail"]]}, "edge_ingestion": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["ING-E2", "51-4062", "Patternmakers, Metal and Plastic", "CA", "94501", "Regular Full time (FT)", "E", "$41,900.00", "E2", "exempt as single letter ''E'' -> exempt, out of scope"], ["ING-E2b", "43-3031", "Bookkeeping, Accounting, and Auditing Clerks", "CA", "94501", "Regular Full time (FT)", "N", "$32,000.00", "E2", "''N'' -> non-exempt, in scope"], ["", "13-1051", "Warehouse Lead", "TX", "75751", "Regular Full time (FT)", "Non-Exempt", "$40,000.00", "E3", "blank Code but carries data -> FLAGGED+REJECTED, not dropped"], ["ING-DUP", "51-6011", "Laundry and Dry-Cleaning Workers", "IL", "62311", "Regular Full time (FT)", "Non-Exempt", "$23,800.00", "E5", "duplicate Code (see next) -> disambiguated"], ["ING-DUP", "27-2032", "Choreographers", "IL", "62311", "Regular Full time (FT)", "Non-Exempt", "$23,300.00", "E5", "duplicate Code (see next) -> disambiguated"]]}, "edge_psl": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["PSL-E18", "29-1181", "Audiologists", "TX", "75751", "Regular Full time (FT)", "Non-Exempt", "$60,000.00", "E18", "TX preempted -> PSL floor 0"], ["PSL-E19", "15-1299", "Penetration Testers", "WA", "98832", "Regular Full time (FT)", "Non-Exempt", "$58,100.00", "E19", "WA no-cap -> floor 0"], ["PSL-E20a", "53-3053", "Shuttle Drivers and Chauffeurs", "CA", "94501", "Regular Full time (FT)", "Non-Exempt", "$27,500.00", "E20", "CA 40h floor -> gap costed"], ["PSL-E20b", "47-2081", "Drywall and Ceiling Tile Installers", "NY", "12009", "Regular Full time (FT)", "Non-Exempt", "$35,700.00", "E20", "NY 56h floor -> gap costed"], ["PSL-E21", "53-5031", "Ship Engineers", "CA", "94501", "Regular Part time (PT)", "Non-Exempt", "$22,880.00", "E21", "part-time 1040h -> entitlement prorated to 2080h (50%)"]]}, "scale_large": {"headers": ["code", "soc", "title", "state", "zip", "class", "exempt", "comp", "edge", "expected"], "rows": [["SCL-001", "25-1062", "Area, Ethnic, and Cultural Studies Teachers, Postsecondary", "AK", "99588", "Regular Full time (FT)", "Non-Exempt", "$79,800.00", "-", "coverage sweep row"], ["SCL-002", "19-4071", "Forest and Conservation Technicians", "AL", "36005", "Regular Full time (FT)", "Non-Exempt", "$54,300.00", "-", "coverage sweep row"], ["SCL-003", "17-2199", "Mechatronics Engineers", "AL", "36009", "Regular Full time (FT)", "Non-Exempt", "$69,300.00", "-", "coverage sweep row"], ["SCL-004", "17-1011", "Architects, Except Landscape and Naval", "AL", "35010", "Regular Full time (FT)", "Non-Exempt", "$73,000.00", "-", "coverage sweep row"], ["SCL-005", "11-9199", "Brownfield Redevelopment Specialists and Site Managers", "AL", "35006", "Regular Full time (FT)", "Non-Exempt", "$116,800.00", "-", "coverage sweep row"]]}}'::jsonb),
    updated_at = now()
where key = 'dataset_catalog';
